import { createContext, useContext, useEffect, useMemo, useRef, useState } from "react";

import axios from "../api/axios";

const AuthContext = createContext();

const STORAGE_TOKEN_KEY = "token";
const STORAGE_USER_KEY = "user";

export const AuthProvider = ({ children }) => {
  const [token, setToken] = useState(null);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const logoutTimerRef = useRef(null);

  // -----------------------------
  // Helpers: JWT decode + expiry
  // -----------------------------
  const decodeToken = (jwtToken) => {
    try {
      if (!jwtToken) return null;
      const parts = jwtToken.split(".");
      if (parts.length < 2) return null;

      // JWT payload is base64url
      let base64 = parts[1].replace(/-/g, "+").replace(/_/g, "/");
      const pad = base64.length % 4;
      if (pad) base64 += "=".repeat(4 - pad);

      const payloadString = atob(base64);
      return JSON.parse(payloadString);
    } catch {
      return null;
    }
  };

  const isTokenExpired = (jwtToken) => {
    const decoded = decodeToken(jwtToken);
    const exp = decoded?.exp;
    if (!exp) return false;
    return exp * 1000 < Date.now();
  };

  const clearLogoutTimer = () => {
    if (logoutTimerRef.current) {
      clearTimeout(logoutTimerRef.current);
      logoutTimerRef.current = null;
    }
  };

  const scheduleAutoLogout = (jwtToken) => {
    clearLogoutTimer();
    const decoded = decodeToken(jwtToken);
    const exp = decoded?.exp;
    if (!exp) return;

    const expiresIn = exp * 1000 - Date.now();
    if (expiresIn <= 0) {
      logout();
      return;
    }

    logoutTimerRef.current = setTimeout(() => {
      logout();
    }, expiresIn);
  };

  // -----------------------------
  // Login
  // -----------------------------
  // eslint-disable-next-line react-hooks/exhaustive-deps
  const login = async (email, password, rememberMe) => {
    try {
      const response = await axios.post(
        process.env.REACT_APP_LOGIN_ENDPOINT,
        {
          email,
          password,
        }
      );

      const apiToken =
        response?.data?.token ||
        response?.data?.accessToken ||
        response?.data?.jwt ||
        null;

      if (!apiToken) {
        return {
          success: false,
          message: "Server error: token missing",
        };
      }

      const decoded = decodeToken(apiToken);

      // Best-effort user from JWT (assumed fields exist per your requirement)
      const derivedUser = decoded
        ? {
            name: decoded.name || decoded.username || "User",
            email: decoded.email || email,
            role: decoded.role || decoded.userRole || "User",
          }
        : {
            name: "User",
            email,
            role: "User",
          };

      setToken(apiToken);
      setUser(derivedUser);

      if (rememberMe) {
        localStorage.setItem(STORAGE_TOKEN_KEY, apiToken);
        localStorage.setItem(STORAGE_USER_KEY, JSON.stringify(derivedUser));
      } else {
        // Remember Me unchecked: keep session in memory only
        localStorage.removeItem(STORAGE_TOKEN_KEY);
        localStorage.removeItem(STORAGE_USER_KEY);
      }

      scheduleAutoLogout(apiToken);

      return { success: true };
    } catch (error) {
      let message = "Login Failed";

      if (!error.response) {
        message = "Network Error";
      } else if (error.response.status === 400) {
        message = "Invalid Email or Password";
      } else if (error.response.status === 401) {
        message = "Unauthorized";
      } else if (error.response.status >= 500) {
        message = "Server Error";
      }

      return { success: false, message };
    }
  };

  // -----------------------------
  // Logout
  // -----------------------------
  // eslint-disable-next-line react-hooks/exhaustive-deps
  const logout = () => {
    clearLogoutTimer();

    localStorage.removeItem(STORAGE_TOKEN_KEY);
    localStorage.removeItem(STORAGE_USER_KEY);

    setToken(null);
    setUser(null);
  };

  // -----------------------------
  // Restore login state after refresh
  // -----------------------------
  useEffect(() => {
    const storedToken = localStorage.getItem(STORAGE_TOKEN_KEY);
    const storedUser = localStorage.getItem(STORAGE_USER_KEY);

    if (!storedToken) {
      setLoading(false);
      return;
    }

    if (isTokenExpired(storedToken)) {
      logout();
      setLoading(false);
      return;
    }

    setToken(storedToken);

    if (storedUser) {
      try {
        setUser(JSON.parse(storedUser));
      } catch {
        setUser(null);
      }
    } else {
      const decoded = decodeToken(storedToken);
      if (decoded) {
        setUser({
          name: decoded.name || decoded.username || "User",
          email: decoded.email || "",
          role: decoded.role || decoded.userRole || "User",
        });
      }
    }

    scheduleAutoLogout(storedToken);
    setLoading(false);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // If token changes (e.g., login/logout), keep timer in sync
  useEffect(() => {
    if (!token) {
      clearLogoutTimer();
      return;
    }
    scheduleAutoLogout(token);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [token]);

  const value = useMemo(() => {
    return {
      token,
      user,
      loading,
      login,
      logout,
      isAuthenticated: !!token,
    };
  }, [token, user, loading, login, logout]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  return useContext(AuthContext);
};
